create extension if not exists pgcrypto; create extension if not exists vector; create extension if not exists pg_cron; create extension if not exists pg_net;
create table monitored_accounts(id uuid primary key default gen_random_uuid(),platform text not null,platform_user_id text not null,username text not null,display_name text,profile_image_url text,enabled boolean default true,latest_processed_post_id text,created_at timestamptz default now(),updated_at timestamptz default now(),unique(platform,platform_user_id));
create table source_posts(id uuid primary key default gen_random_uuid(),monitored_account_id uuid references monitored_accounts,text text not null,platform text not null default 'x',platform_post_id text not null,post_url text,posted_at timestamptz not null,raw_payload jsonb not null default '{}',public_metrics jsonb not null default '{}',is_relevant boolean,relevance_reason text,approved_public boolean default false,embedding vector(1536),ingested_at timestamptz default now(),unique(platform,platform_post_id));
create table extracted_events(id uuid primary key default gen_random_uuid(),source_post_id uuid references source_posts on delete cascade,extraction_version text not null,event_type text not null,event_payload jsonb not null,extraction_confidence numeric check(extraction_confidence between 0 and 1),requires_review boolean default true,created_at timestamptz default now());
create table known_reset_events(id uuid primary key default gen_random_uuid(),occurred_at timestamptz not null,reset_type text not null,reason_category text,description text not null,source_post_id uuid references source_posts,verified boolean default false,verification_notes text,created_at timestamptz default now());
create table forecast_models(id uuid primary key default gen_random_uuid(),name text not null,version text unique not null,configuration jsonb not null,active boolean default false,created_at timestamptz default now());
create table forecasts(id uuid primary key default gen_random_uuid(),forecast_model_id uuid references forecast_models,generated_at timestamptz not null,horizon_hours integer not null,probability numeric check(probability between 0 and 1),credible_interval_low numeric,credible_interval_high numeric,predicted_window_start timestamptz,predicted_window_end timestamptz,data_cutoff timestamptz not null,feature_snapshot jsonb not null,simulation_summary jsonb not null,evidence_post_ids uuid[] not null default '{}',mode text check(mode in('demo','live')),created_at timestamptz default now());
create table forecast_feature_contributions(id uuid primary key default gen_random_uuid(),forecast_id uuid references forecasts on delete cascade,feature_name text not null,normalized_value numeric not null,coefficient numeric not null,log_odds_contribution numeric not null,display_probability_impact numeric,evidence jsonb default '{}');
create table ingestion_runs(id uuid primary key default gen_random_uuid(),source text not null,started_at timestamptz not null,completed_at timestamptz,status text not null,posts_read int default 0,posts_inserted int default 0,posts_analyzed int default 0,error_message text,metadata jsonb default '{}');
create table historical_backtests(id uuid primary key default gen_random_uuid(),cutoff_at timestamptz not null,horizon_hours int not null,predicted_probability numeric not null,actual_outcome boolean not null,brier_loss numeric not null,model_version text not null,evidence_count int not null,created_at timestamptz default now());
alter table monitored_accounts enable row level security;alter table source_posts enable row level security;alter table extracted_events enable row level security;alter table known_reset_events enable row level security;alter table forecast_models enable row level security;alter table forecasts enable row level security;alter table forecast_feature_contributions enable row level security;alter table ingestion_runs enable row level security;alter table historical_backtests enable row level security;
create policy "public approved source posts" on source_posts for select using(approved_public);create policy "public forecasts" on forecasts for select using(true);create policy "public verified reset events" on known_reset_events for select using(verified);create policy "public aggregate backtests" on historical_backtests for select using(true);create policy "public active model" on forecast_models for select using(active);create policy "public contributions" on forecast_feature_contributions for select using(true);
alter publication supabase_realtime add table forecasts;
